import{_ as a,o as n,c as l,ag as e}from"./chunks/framework.DXGyWiRo.js";const D=JSON.parse('{"title":"FlashQL","description":"","frontmatter":{},"headers":[],"relativePath":"flashql.md","filePath":"flashql.md"}'),o={name:"flashql.md"};function t(p,s,r,c,i,y){return n(),l("div",null,[...s[0]||(s[0]=[e(`<h1 id="flashql" tabindex="-1">FlashQL <a class="header-anchor" href="#flashql" aria-label="Permalink to &quot;FlashQL&quot;">​</a></h1><p><em>A full SQL runtime for the local process, the browser, the edge, and the offline world.</em></p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> db </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;"> new</span><span style="color:#82AAFF;"> FlashQL</span><span style="color:#BABED8;">()</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">\`</span><span style="color:#C3E88D;">SELECT $1::TEXT</span><span style="color:#89DDFF;">\`</span><span style="color:#89DDFF;">,</span><span style="color:#BABED8;"> [</span><span style="color:#F78C6C;">20</span><span style="color:#BABED8;">])</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>FlashQL is LinkedQL&#39;s embeddable database engine: a complete in-process SQL runtime that runs anywhere JavaScript does, including Node.js, the browser, workers, and edge runtimes.</p><p>FlashQL brings together:</p><p><strong>Core engine</strong></p><ul><li>a full relational SQL engine</li><li>transactional local storage with MVCC</li></ul><p><strong>Reactive and realtime</strong></p><ul><li>live queries</li><li>observable commit stream (WAL)</li></ul><p><strong>Distributed data</strong></p><ul><li>federation, materialization, and sync</li></ul><p><strong>Time and history</strong></p><ul><li>point-in-time boot via version-aware replay</li></ul><hr><h2 id="why-flashql" tabindex="-1">Why FlashQL <a class="header-anchor" href="#why-flashql" aria-label="Permalink to &quot;Why FlashQL&quot;">​</a></h2><p>Modern applications increasingly need database power in places where a traditional database server is inconvenient, expensive, unavailable, or simply the wrong abstraction.</p><p>FlashQL directly maps to those use cases. Where the database is traditionally a remote dependency, FlashQL brings it into the application runtime.</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#89DDFF;font-style:italic;">import</span><span style="color:#89DDFF;"> {</span><span style="color:#BABED8;"> FlashQL</span><span style="color:#89DDFF;"> }</span><span style="color:#89DDFF;font-style:italic;"> from</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">@linked-db/linked-ql/flashql</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> db </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;"> new</span><span style="color:#82AAFF;"> FlashQL</span><span style="color:#BABED8;">()</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">connect</span><span style="color:#BABED8;">()</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> result </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">SELECT 2::text AS value</span><span style="color:#89DDFF;">&#39;</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#BABED8;">console</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">log</span><span style="color:#BABED8;">(result</span><span style="color:#89DDFF;">.</span><span style="color:#BABED8;">rows)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;">// [{ value: &#39;2&#39; }]</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">disconnect</span><span style="color:#BABED8;">()</span><span style="color:#89DDFF;">;</span></span></code></pre></div><hr><h2 id="persistence" tabindex="-1">Persistence <a class="header-anchor" href="#persistence" aria-label="Permalink to &quot;Persistence&quot;">​</a></h2><p>FlashQL is ephemeral by default, but it becomes a persistent local runtime when you attach a <code>keyval</code> backend.</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#89DDFF;font-style:italic;">import</span><span style="color:#89DDFF;"> {</span><span style="color:#BABED8;"> FlashQL</span><span style="color:#89DDFF;"> }</span><span style="color:#89DDFF;font-style:italic;"> from</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">@linked-db/linked-ql/flashql</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">import</span><span style="color:#89DDFF;"> {</span><span style="color:#BABED8;"> IndexedDBKV</span><span style="color:#89DDFF;"> }</span><span style="color:#89DDFF;font-style:italic;"> from</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">@webqit/keyval/indexeddb</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> db </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;"> new</span><span style="color:#82AAFF;"> FlashQL</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#F07178;">  keyval</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> new</span><span style="color:#82AAFF;"> IndexedDBKV</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">{</span><span style="color:#F07178;"> path</span><span style="color:#89DDFF;">:</span><span style="color:#BABED8;"> [</span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">my-app</span><span style="color:#89DDFF;">&#39;</span><span style="color:#BABED8;">] </span><span style="color:#89DDFF;">}</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#89DDFF;">}</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">connect</span><span style="color:#BABED8;">()</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>With a <code>keyval</code> backend:</p><ul><li>schema and data survive reloads</li><li>WAL history is persisted</li><li>sync state is persisted</li><li>FlashQL becomes appropriate for browser PWAs and local-first applications</li></ul><p>But a persistence backend is not always necessary when used for tests, ephemeral sessions, and in-process computation.</p><hr><h2 id="dialects" tabindex="-1">Dialects <a class="header-anchor" href="#dialects" aria-label="Permalink to &quot;Dialects&quot;">​</a></h2><p>FlashQL supports both PostgreSQL-flavored and MySQL-flavored SQL.</p><p>Set a default dialect at the client level:</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> db </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;"> new</span><span style="color:#82AAFF;"> FlashQL</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">{</span><span style="color:#F07178;"> dialect</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">postgres</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;"> }</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>Optionally override it per query:</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">SELECT \`name\` FROM \`users\`</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span><span style="color:#89DDFF;"> {</span><span style="color:#F07178;"> dialect</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">mysql</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;"> }</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>Where not specified, FlashQL defaults to <code>postgres</code>.</p><hr><h2 id="the-common-query-surface" tabindex="-1">The Common Query Surface <a class="header-anchor" href="#the-common-query-surface" aria-label="Permalink to &quot;The Common Query Surface&quot;">​</a></h2><p>FlashQL supports the same top-level application contract as the other LinkedQL clients:</p><ul><li><code>db.query()</code></li><li><code>db.query({ live: true })</code></li><li><code>db.stream()</code></li><li><code>db.transaction()</code></li><li><code>db.wal.subscribe()</code></li></ul><p>And then extends that with:</p><ul><li><code>db.sync.sync()</code></li></ul><hr><h2 id="live-queries-streams-and-the-commit-stream-wal" tabindex="-1">Live Queries, Streams, and the Commit Stream (WAL) <a class="header-anchor" href="#live-queries-streams-and-the-commit-stream-wal" aria-label="Permalink to &quot;Live Queries, Streams, and the Commit Stream (WAL)&quot;">​</a></h2><p>FlashQL supports modern application data flows directly.</p><h3 id="live-queries" tabindex="-1">Live Queries <a class="header-anchor" href="#live-queries" aria-label="Permalink to &quot;Live Queries&quot;">​</a></h3><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> result </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span></span>
<span class="line"><span style="color:#89DDFF;">  &#39;</span><span style="color:#C3E88D;">SELECT id, name FROM public.users ORDER BY id</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#89DDFF;">  {</span><span style="color:#F07178;"> live</span><span style="color:#89DDFF;">:</span><span style="color:#FF9CAC;"> true</span><span style="color:#89DDFF;"> }</span></span>
<span class="line"><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#BABED8;">console</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">log</span><span style="color:#BABED8;">(result</span><span style="color:#89DDFF;">.</span><span style="color:#BABED8;">rows)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;">// current rows; the array keeps tracking the query as local state changes</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> result</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">abort</span><span style="color:#BABED8;">()</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>Use live queries when the application wants the query result itself to remain current over time.</p><p>Take a deep dive in:</p><ul><li><a href="/realtime/live-queries">Live Queries</a></li></ul><h3 id="streaming" tabindex="-1">Streaming <a class="header-anchor" href="#streaming" aria-label="Permalink to &quot;Streaming&quot;">​</a></h3><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#89DDFF;font-style:italic;">for</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> (</span><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> row </span><span style="color:#89DDFF;">of</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">stream</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">SELECT * FROM public.big_table ORDER BY id</span><span style="color:#89DDFF;">&#39;</span><span style="color:#BABED8;">)) </span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#BABED8;">  console</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">log</span><span style="color:#F07178;">(</span><span style="color:#BABED8;">row</span><span style="color:#F07178;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#89DDFF;">}</span></span></code></pre></div><p>This lets you consume large results lazily instead of buffering the full result in memory first.</p><p>See more in <a href="/api/stream">db.stream()</a></p><h3 id="the-commit-stream-wal" tabindex="-1">The Commit Stream (WAL) <a class="header-anchor" href="#the-commit-stream-wal" aria-label="Permalink to &quot;The Commit Stream (WAL)&quot;">​</a></h3><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> sub </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#BABED8;">wal</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">subscribe</span><span style="color:#BABED8;">(</span></span>
<span class="line"><span style="color:#89DDFF;">  {</span><span style="color:#F07178;"> public</span><span style="color:#89DDFF;">:</span><span style="color:#BABED8;"> [</span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">users</span><span style="color:#89DDFF;">&#39;</span><span style="color:#BABED8;">] </span><span style="color:#89DDFF;">},</span></span>
<span class="line"><span style="color:#89DDFF;">  (</span><span style="color:#BABED8;font-style:italic;">commit</span><span style="color:#89DDFF;">)</span><span style="color:#C792EA;"> =&gt;</span><span style="color:#BABED8;"> console</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">log</span><span style="color:#BABED8;">(commit)</span></span>
<span class="line"><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> sub</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">abort</span><span style="color:#BABED8;">()</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>This lets you subscribe to table-level commits directly.</p><p>See: <a href="/realtime/changefeeds">Changefeeds</a></p><hr><h2 id="transactions-and-the-multi-version-concurrency-control-mvcc-architecture" tabindex="-1">Transactions and the Multi-Version Concurrency Control (MVCC) Architecture <a class="header-anchor" href="#transactions-and-the-multi-version-concurrency-control-mvcc-architecture" aria-label="Permalink to &quot;Transactions and the Multi-Version Concurrency Control (MVCC) Architecture&quot;">​</a></h2><p>FlashQL uses <strong>Multi-Version Concurrency Control (MVCC)</strong>, the same core model used by PostgreSQL.</p><p>Every write creates a new version of a row, and every transaction reads from a <strong>consistent snapshot in time</strong>.</p><p>While you don&#39;t think about it, each query you run</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span></span>
<span class="line"><span style="color:#89DDFF;">  \`</span><span style="color:#C3E88D;">INSERT INTO public.users (id, name)</span></span>
<span class="line"><span style="color:#C3E88D;">  VALUES (1, &#39;Ada&#39;);</span></span>
<span class="line"><span style="color:#C3E88D;">  DELETE FROM public.orders WHERE id = 2;</span><span style="color:#89DDFF;">\`</span></span>
<span class="line"><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>executes within a transaction. Errors are isolated to that transaction, and the entire operation is automatically rolled back on error.</p><p>Internally:</p><ul><li>transactions don’t overwrite rows—they produce new versions</li><li>each transaction sees a stable view of the database</li><li>reads and writes don’t block each other</li></ul><p>If you’ve used PostgreSQL, this is the same idea—just running locally, in-process.</p><p>Because everything is versioned, FlashQL can layer on:</p><ul><li><strong>a row-version-aware sync engine</strong></li><li><strong>WAL-based change streams</strong></li><li><strong>replay and point-in-time boot</strong></li></ul><p>—all without introducing a separate model for reactivity or sync.</p><hr><h2 id="federation-materialization-and-sync" tabindex="-1">Federation, Materialization, and Sync <a class="header-anchor" href="#federation-materialization-and-sync" aria-label="Permalink to &quot;Federation, Materialization, and Sync&quot;">​</a></h2><p>FlashQL can compute both local and remote data in <strong>the same query</strong>.</p><p>You simply define remote data locally; you decide how it behaves.</p><p>Your code sees normal tables:</p><div class="language-sql"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#F78C6C;">SELECT</span><span style="color:#89DDFF;"> *</span></span>
<span class="line"><span style="color:#F78C6C;">FROM</span><span style="color:#BABED8;"> public.local_users u</span></span>
<span class="line"><span style="color:#F78C6C;">JOIN</span><span style="color:#BABED8;"> public.remote_orders o </span><span style="color:#F78C6C;">ON</span><span style="color:#BABED8;"> o.user_id </span><span style="color:#89DDFF;">=</span><span style="color:#BABED8;"> u.id;</span></span></code></pre></div><p>FlashQL computes the local + remote data as one relational graph.</p><p>Take a deep dive in:</p><ul><li><a href="/flashql/federation-and-sync">Federation, Materialization, and Sync</a></li><li><a href="/flashql/sync-api">The Sync API</a></li></ul><hr><h2 id="point-in-time-boot" tabindex="-1">Point-in-Time Boot <a class="header-anchor" href="#point-in-time-boot" aria-label="Permalink to &quot;Point-in-Time Boot&quot;">​</a></h2><p>FlashQL can boot itself to a point in history – the state of the database at a certain table name and version.</p><h3 id="read-only-historical-boot" tabindex="-1">Read-Only Historical Boot <a class="header-anchor" href="#read-only-historical-boot" aria-label="Permalink to &quot;Read-Only Historical Boot&quot;">​</a></h3><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> historical </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;"> new</span><span style="color:#82AAFF;"> FlashQL</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#BABED8;">  keyval</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#F07178;">  versionStop</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">public.snap_tbl@1</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#89DDFF;">}</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> historical</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">connect</span><span style="color:#BABED8;">()</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>With <code>versionStop</code>, FlashQL replays itself to the time when the database had the specified table at the specified version.</p><p>The effect is that the runtime boots against that historical boundary instead of replaying all the way forward to the latest state.</p><p>By default, that boot is read-only. Rewriting the hostory from that point forward is possible with an explicit opt-in:</p><h4 id="overwriteforward-true" tabindex="-1"><code>overwriteForward: true</code> <a class="header-anchor" href="#overwriteforward-true" aria-label="Permalink to &quot;\`overwriteForward: true\`&quot;">​</a></h4><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> branch </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;"> new</span><span style="color:#82AAFF;"> FlashQL</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#BABED8;">  keyval</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#F07178;">  versionStop</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">public.snap_tbl@1</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#F07178;">  overwriteForward</span><span style="color:#89DDFF;">:</span><span style="color:#FF9CAC;"> true</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#89DDFF;">}</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> branch</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">connect</span><span style="color:#BABED8;">()</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>With <code>overwriteForward: true</code>, FlashQL keeps the history intact until the first mutating commit is made, then truncates forward histories and lets you continue from that historical point.</p><p>That turns the historical boot into a branch point: read-only until the first write, then writable from that point forward.</p><hr><h2 id="additional-reading" tabindex="-1">Additional Reading <a class="header-anchor" href="#additional-reading" aria-label="Permalink to &quot;Additional Reading&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">If you want to learn about...</th><th style="text-align:left;">Go to...</th></tr></thead><tbody><tr><td style="text-align:left;">the FlashQL sync story in detail</td><td style="text-align:left;"><a href="/flashql/federation-and-sync">Federation, Materialization, and Sync</a></td></tr><tr><td style="text-align:left;">FlashQL language surface</td><td style="text-align:left;"><a href="/flashql/lang">FlashQL Language Surface</a></td></tr></tbody></table>`,92)])])}const d=a(o,[["render",t]]);export{D as __pageData,d as default};
